import React from 'react'
import styled from 'styled-components'

const SidebarWrapper = styled.div `
display:flex;
flex-direction:column;
align-items:flex-start;
justify-content:center;
width:100%;
border:1px solid yellow;
`
const DepartmentWrapper = styled.div `
margin:10px 0;
display:flex;
flex-direction:column;
`

const DepartmentTitle = styled.span `
font-size:0.9rem;

`

const CategoryWrapper = styled.div `
margin:10px 0;
display:flex;
flex-direction:column;
`

const SizeWrapper = styled.div `
margin:10px 0;
display:flex;
flex-direction:column;
`

const DesignerWrapper = styled.div `
margin:10px 0;
display:flex;
flex-direction:column;
`

const PriceWrapper = styled.div `
margin:10px 0;
display:flex;
flex-direction:column;
`

const ConditionWrapper = styled.div `
margin:10px 0;
display:flex;
flex-direction:column;
`

const SidebarTitles = styled.div `
font-size:1.2rem;
font-weight:700;
`

const SeparationBar = styled.div `
width:100%;
`

const Checkbox = styled.input ``

const MenswearTitle = styled.div `
font-wieght:700;
font-size:0.7rem;
`

const MenswearSection = styled.div `
display:flex;
flex-direction:column;
`

const WomenswearSection = styled.div `
display:flex;
flex-direction:column;
`

const Catogories = styled.div `
display:flex;
flex-direction:column;
`

const Category = styled.div `
margin:10px 0;
display:flex;
justify-content:space-between;
`

const Name = styled.div `
font-size:0.5rem;
`

const Arrow = styled.div `
width:15%;
height:100%;
background-color:#1C1C1C;
clip-path: polygon(0 40%, 50% 85%, 100% 40%, 100% 55%, 50% 100%, 0 55%);
`


export default function Sidebar () {
	return (
		<SidebarWrapper>
			<DepartmentWrapper>
				<SidebarTitles>Department</SidebarTitles>
				<label><Checkbox type='checkbox' value='Menswear'/><DepartmentTitle>Menswear</DepartmentTitle></label>
				<label><Checkbox type='checkbox' value='womenswear'/><DepartmentTitle>Womenswear</DepartmentTitle></label>
			</DepartmentWrapper>
			<SeparationBar/>
			<CategoryWrapper>
				<SidebarTitles>Category</SidebarTitles>
				<MenswearSection>
					<MenswearTitle>Menswear</MenswearTitle>
					<Catogories>
						<Category>
							<Name></Name>
							<Arrow></Arrow>
						</Category>
					</Catogories>
				</MenswearSection>
				<WomenswearSection></WomenswearSection>
			</CategoryWrapper>
			<SeparationBar/>
			<SizeWrapper>
				<SidebarTitles>Size</SidebarTitles>
			</SizeWrapper>
			<SeparationBar/>
			<DesignerWrapper>
				<SidebarTitles>Designer</SidebarTitles>
			</DesignerWrapper>
			<SeparationBar/>
			<PriceWrapper>
				<SidebarTitles>Price</SidebarTitles>
			</PriceWrapper>
			<SeparationBar/>
			<ConditionWrapper>
				<SidebarTitles>Condition</SidebarTitles>
			</ConditionWrapper>
			<SeparationBar/>
		</SidebarWrapper>
	)
}
